package store

import (
	"os"
	"strings"
	"sync"

	"k8s.io/klog/v2"
)

const (
	redisStoreType  string = "redis"
	valkeyStoreType string = "valkey"
)

var (
	initStoreOnce = &sync.Once{}
	provider      Store
)

func Storage() Store {
	initStoreOnce.Do(initStore)
	return provider
}

func initStore() error {
	storeType := strings.ToLower(os.Getenv("STORE_TYPE"))
	if storeType == "" {
		storeType = redisStoreType
	}

	var err error
	switch storeType {
	case redisStoreType:
		provider, err = newRedisStore()
	case valkeyStoreType:
		provider, err = newValkeyStore()
	default:
		return &StoreError{Message: "unsupported store type: " + storeType}
	}

	if err != nil {
		return err
	}

	return nil
}

type StoreError struct {
	Message string
}

func (e *StoreError) Error() string {
	return e.Message
}

package store

import (
	"os"
	"strings"
	"sync"
)

const (
	redisStoreType  string = "redis"
	valkeyStoreType string = "valkey"
)

var (
	initStoreOnce = &sync.Once{}
	provider      Store
)

func Storage() Store {
	initStoreOnce.Do(func() {
		if err := initStore(); err != nil {
			panic(err)
		}
	})
	return provider
}

func initStore() error {
	storeType := strings.ToLower(os.Getenv("STORE_TYPE"))
	if storeType == "" {
		storeType = redisStoreType
	}

	var err error
	switch storeType {
	case redisStoreType:
		provider, err = newRedisStore()
	case valkeyStoreType:
		provider, err = newValkeyStore()
	default:
		return &StoreError{Message: "unsupported store type: " + storeType}
	}

	if err != nil {
		return err
	}

	return nil
}

type StoreError struct {
	Message string
}

func (e *StoreError) Error() string {
	return e.Message
}

package store

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"strconv"
	"time"

	redisv9 "github.com/redis/go-redis/v9"
	"github.com/volcano-sh/agentcube/pkg/common/types"
)

type redisStore struct {
	cli                  *redisv9.Client
	sessionPrefix        string
	expiryIndexKey       string
	lastActivityIndexKey string
}

const (
	sessionPrefix        = "session:"
	expiryIndexKey       = "session:expiry"
	lastActivityIndexKey = "session:last_activity"
)

func newRedisStore() (*redisStore, error) {
	redisAddr := os.Getenv("REDIS_ADDR")
	if redisAddr == "" {
		return nil, &StoreError{Message: "REDIS_ADDR environment variable is not set"}
	}

	redisPassword := os.Getenv("REDIS_PASSWORD")
	passwordRequired := true
	if val := os.Getenv("REDIS_PASSWORD_REQUIRED"); val != "" {
		passwordRequired = val != "false" && val != "FALSE" && val != "False"
	}

	if redisPassword == "" && passwordRequired {
		return nil, &StoreError{Message: "REDIS_PASSWORD is required but not set"}
	}

	opts := makeRedisOptions(redisAddr, redisPassword)
	client := redisv9.NewClient(opts)

	return &redisStore{
		cli:                  client,
		sessionPrefix:        sessionPrefix,
		expiryIndexKey:       expiryIndexKey,
		lastActivityIndexKey: lastActivityIndexKey,
	}, nil
}

func makeRedisOptions(addr, password string) *redisv9.Options {
	return &redisv9.Options{
		Addr:     addr,
		Password: password,
	}
}

func (rs *redisStore) Ping(ctx context.Context) error {
	pong, err := rs.cli.Ping(ctx).Result()
	if err != nil {
		return err
	}
	if pong != "PONG" {
		return &StoreError{Message: "unexpected ping response: " + pong}
	}
	return nil
}

func (rs *redisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := rs.sessionKey(sessionID)
	data, err := rs.cli.Get(ctx, key).Result()
	if err == redisv9.Nil {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
		return nil, err
	}

	return &sandbox, nil
}

func (rs *redisStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return &StoreError{Message: "sandbox cannot be nil"}
	}
	if sandbox.ExpiresAt.IsZero() {
		return &StoreError{Message: "sandbox ExpiresAt cannot be zero"}
	}

	key := rs.sessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	pipe := rs.cli.Pipeline()
	setCmd := pipe.SetNX(ctx, key, data, 0)
	expiryCmd := pipe.ZAdd(ctx, rs.expiryIndexKey, redisv9.Z{
		Score:  float64(sandbox.ExpiresAt.Unix()),
		Member: sandbox.SessionID,
	})
	activityCmd := pipe.ZAdd(ctx, rs.lastActivityIndexKey, redisv9.Z{
		Score:  float64(time.Now().Unix()),
		Member: sandbox.SessionID,
	})

	_, err = pipe.Exec(ctx)
	if err != nil {
		return err
	}

	if !setCmd.Val() {
		return &StoreError{Message: "session already exists"}
	}

	_ = expiryCmd
	_ = activityCmd
	return nil
}

func (rs *redisStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return &StoreError{Message: "sandbox cannot be nil"}
	}

	key := rs.sessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	setCmd := rs.cli.Set(ctx, key, data, 0)
	if setCmd.Err() != nil {
		return setCmd.Err()
	}

	val, err := rs.cli.Get(ctx, key).Result()
	if err == redisv9.Nil {
		return &StoreError{Message: "key not exists"}
	}
	if err != nil {
		return err
	}
	if val == "" {
		return &StoreError{Message: "key not exists"}
	}

	return nil
}

func (rs *redisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := rs.sessionKey(sessionID)

	pipe := rs.cli.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, rs.expiryIndexKey, sessionID)
	pipe.ZRem(ctx, rs.lastActivityIndexKey, sessionID)

	_, err := pipe.Exec(ctx)
	return err
}

func (rs *redisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}

	zCmd := rs.cli.ZRangeByScore(ctx, rs.expiryIndexKey, &redisv9.ZRangeBy{
		Min: "-inf",
		Max: strconv.FormatInt(before.Unix(), 10),
		Offset: 0,
		Count:  limit,
	})

	sessionIDs, err := zCmd.Result()
	if err != nil {
		return nil, err
	}

	return rs.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (rs *redisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}

	zCmd := rs.cli.ZRangeByScore(ctx, rs.lastActivityIndexKey, &redisv9.ZRangeBy{
		Min: "-inf",
		Max: strconv.FormatInt(before.Unix(), 10),
		Offset: 0,
		Count:  limit,
	})

	sessionIDs, err := zCmd.Result()
	if err != nil {
		return nil, err
	}

	return rs.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (rs *redisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return &StoreError{Message: "sessionID cannot be empty"}
	}

	if at.IsZero() {
		at = time.Now()
	}

	key := rs.sessionKey(sessionID)
	existsCmd := rs.cli.Exists(ctx, key)
	exists, err := existsCmd.Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	zCmd := rs.cli.ZAdd(ctx, rs.lastActivityIndexKey, redisv9.Z{
		Score:  float64(at.Unix()),
		Member: sessionID,
	})
	return zCmd.Err()
}

func (rs *redisStore) Close() error {
	if rs.cli != nil {
		return rs.cli.Close()
	}
	return nil
}

func (rs *redisStore) sessionKey(sessionID string) string {
	return rs.sessionPrefix + sessionID
}

func (rs *redisStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, sid := range sessionIDs {
		keys[i] = rs.sessionKey(sid)
	}

	getCmds := rs.cli.Pipeline()
	cmds := make([]*redisv9.StringCmd, len(keys))
	for i, key := range keys {
		cmds[i] = getCmds.Get(ctx, key)
	}

	_, err := getCmds.Exec(ctx)
	if err != nil && err != redisv9.Nil {
		return nil, err
	}

	var result []*types.SandboxInfo
	for i, cmd := range cmds {
		val, err := cmd.Result()
		if err == redisv9.Nil {
			continue
		}
		if err != nil {
			continue
		}

		var sandbox types.SandboxInfo
		if err := json.Unmarshal([]byte(val), &sandbox); err != nil {
			continue
		}
		result = append(result, &sandbox)
		_ = i
	}

	return result, nil
}

package store

import (
	"context"
	"encoding/json"
	"os"
	"strconv"
	"strings"
	"time"

	"github.com/valkey-io/valkey-go"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"k8s.io/klog/v2"
)

type valkeyStore struct {
	cli                  valkey.Client
	sessionPrefix        string
	expiryIndexKey       string
	lastActivityIndexKey string
}

func newValkeyStore() (*valkeyStore, error) {
	valkeyAddr := os.Getenv("VALKEY_ADDR")
	if valkeyAddr == "" {
		return nil, &StoreError{Message: "VALKEY_ADDR environment variable is not set"}
	}

	valkeyPassword := os.Getenv("VALKEY_PASSWORD")
	passwordRequired := true
	if val := os.Getenv("VALKEY_PASSWORD_REQUIRED"); val != "" {
		passwordRequired = val != "false" && val != "FALSE" && val != "False"
	}

	if valkeyPassword == "" && passwordRequired {
		return nil, &StoreError{Message: "VALKEY_PASSWORD is required but not set"}
	}

	opts, err := makeValkeyOptions(valkeyAddr, valkeyPassword)
	if err != nil {
		return nil, err
	}

	client, err := valkey.NewClient(*opts)
	if err != nil {
		return nil, err
	}

	return &valkeyStore{
		cli:                  client,
		sessionPrefix:        sessionPrefix,
		expiryIndexKey:       expiryIndexKey,
		lastActivityIndexKey: lastActivityIndexKey,
	}, nil
}

func makeValkeyOptions(addr, password string) (*valkey.ClientOption, error) {
	opts := &valkey.ClientOption{
		InitAddress: strings.Split(addr, ","),
		Password:    password,
	}

	if val := os.Getenv("VALKEY_DISABLE_CACHE"); val != "" {
		disable, err := strconv.ParseBool(val)
		if err != nil {
			return nil, &StoreError{Message: "VALKEY_DISABLE_CACHE must be a boolean"}
		}
		if disable {
			opts.DisableCache = true
		}
	}

	if val := os.Getenv("VALKEY_FORCE_SINGLE"); val != "" {
		force, err := strconv.ParseBool(val)
		if err != nil {
			return nil, &StoreError{Message: "VALKEY_FORCE_SINGLE must be a boolean"}
		}
		if force {
			opts.ForceSingleClient = true
		}
	}

	return opts, nil
}

func (vs *valkeyStore) Ping(ctx context.Context) error {
	result := vs.cli.B().Ping().Build()
	resp, err := vs.cli.Do(ctx, result).ToString()
	if err != nil {
		return err
	}
	if resp != "PONG" {
		return &StoreError{Message: "unexpected ping response: " + resp}
	}
	return nil
}

func (vs *valkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := vs.sessionKey(sessionID)
	result := vs.cli.B().Get().Key(key).Build()
	data, err := vs.cli.Do(ctx, result).ToString()
	if valkey.IsValkeyNil(err) {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
		return nil, err
	}

	return &sandbox, nil
}

func (vs *valkeyStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return &StoreError{Message: "sandbox cannot be nil"}
	}
	if sandbox.ExpiresAt.IsZero() {
		return &StoreError{Message: "sandbox ExpiresAt cannot be zero"}
	}

	key := vs.sessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	commands := vs.cli.B().Arbitrary().Commands(
		"SETNX", key, string(data),
		"ZADD", vs.expiryIndexKey, strconv.FormatFloat(float64(sandbox.ExpiresAt.Unix()), 'f', -1, 64), sandbox.SessionID,
		"ZADD", vs.lastActivityIndexKey, strconv.FormatFloat(float64(time.Now().Unix()), 'f', -1, 64), sandbox.SessionID,
	).Build()

	result := vs.cli.DoMulti(ctx, commands)
	for _, resp := range result {
		if resp.Error() != nil {
			return resp.Error()
		}
	}

	return nil
}

func (vs *valkeyStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return &StoreError{Message: "sandbox cannot be nil"}
	}

	key := vs.sessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	result := vs.cli.B().Set().Key(key).Value(string(data)).Xx().Build()
	resp, err := vs.cli.Do(ctx, result).ToString()
	if err != nil {
		return err
	}
	if resp != "OK" {
		return &StoreError{Message: "key not exists"}
	}

	return nil
}

func (vs *valkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := vs.sessionKey(sessionID)

	commands := vs.cli.B().Arbitrary().Commands(
		"DEL", key,
		"ZREM", vs.expiryIndexKey, sessionID,
		"ZREM", vs.lastActivityIndexKey, sessionID,
	).Build()

	result := vs.cli.DoMulti(ctx, commands)
	for _, resp := range result {
		if resp.Error() != nil {
			return resp.Error()
		}
	}

	return nil
}

func (vs *valkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}

