	valkeyPassword := os.Getenv("VALKEY_PASSWORD")
	passwordRequired := true
	if val := os.Getenv("VALKEY_PASSWORD_REQUIRED"); val != "" {
		passwordRequired = val != "false" && val != "FALSE" && val != "False"
	}

	if valkeyPassword == "" && passwordRequired {
		return nil, &StoreError{Message: "VALKEY_PASSWORD is required but not set"}
	}

	opts, err := makeValkeyOptions(valkeyAddr, valkeyPassword)
	if err != nil {
		return nil, err
	}

	client, err := valkey.NewClient(*opts)
	if err != nil {
		return nil, err
	}

	return &valkeyStore{
		cli:                  client,
		sessionPrefix:        sessionPrefix,
		expiryIndexKey:       expiryIndexKey,
		lastActivityIndexKey: lastActivityIndexKey,
	}, nil
}

func makeValkeyOptions(addr, password string) (*valkey.ClientOption, error) {
	opts := &valkey.ClientOption{
		InitAddress: strings.Split(addr, ","),
		Password:    password,
	}

	if val := os.Getenv("VALKEY_DISABLE_CACHE"); val != "" {
		disable, err := strconv.ParseBool(val)
		if err != nil {
			return nil, &StoreError{Message: "VALKEY_DISABLE_CACHE must be a boolean"}
		}
		if disable {
			opts.DisableCache = true
		}
	}

	if val := os.Getenv("VALKEY_FORCE_SINGLE"); val != "" {
		force, err := strconv.ParseBool(val)
		if err != nil {
			return nil, &StoreError{Message: "VALKEY_FORCE_SINGLE must be a boolean"}
		}
		if force {
			opts.ForceSingleClient = true
		}
	}

	return opts, nil
}

func (vs *valkeyStore) Ping(ctx context.Context) error {
	result := vs.cli.B().Ping().Build()
	resp, err := vs.cli.Do(ctx, result).ToString()
	if err != nil {
		return err
	}
	if resp != "PONG" {
		return &StoreError{Message: "unexpected ping response: " + resp}
	}
	return nil
}

func (vs *valkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := vs.sessionKey(sessionID)
	result := vs.cli.B().Get().Key(key).Build()
	data, err := vs.cli.Do(ctx, result).ToString()
	if valkey.IsValkeyNil(err) {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
		return nil, err
	}

	return &sandbox, nil
}

func (vs *valkeyStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return &StoreError{Message: "sandbox cannot be nil"}
	}
	if sandbox.ExpiresAt.IsZero() {
		return &StoreError{Message: "sandbox ExpiresAt cannot be zero"}
	}

	key := vs.sessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	setCmd := vs.cli.B().Setnx().Key(key).Value(string(data)).Build()
	zaddExpiryCmd := vs.cli.B().Zadd().Key(vs.expiryIndexKey).ScoreMember().ScoreMember(float64(sandbox.ExpiresAt.Unix()), sandbox.SessionID).Build()
	zaddActivityCmd := vs.cli.B().Zadd().Key(vs.lastActivityIndexKey).ScoreMember().ScoreMember(float64(time.Now().Unix()), sandbox.SessionID).Build()

	results := vs.cli.DoMulti(ctx, setCmd, zaddExpiryCmd, zaddActivityCmd)
	for _, resp := range results {
		if resp.Error() != nil {
			return resp.Error()
		}
	}

	return nil
}

func (vs *valkeyStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return &StoreError{Message: "sandbox cannot be nil"}
	}

	key := vs.sessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	result := vs.cli.B().Set().Key(key).Value(string(data)).Xx().Build()
	resp, err := vs.cli.Do(ctx, result).ToString()
	if err != nil {
		return err
	}
	if resp != "OK" {
		return &StoreError{Message: "key not exists"}
	}

	return nil
}

func (vs *valkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := vs.sessionKey(sessionID)

	delCmd := vs.cli.B().Del().Key(key).Build()
	zremExpiryCmd := vs.cli.B().Zrem().Key(vs.expiryIndexKey).Member(sessionID).Build()
	zremActivityCmd := vs.cli.B().Zrem().Key(vs.lastActivityIndexKey).Member(sessionID).Build()

	results := vs.cli.DoMulti(ctx, delCmd, zremExpiryCmd, zremActivityCmd)
	for _, resp := range results {
		if resp.Error() != nil {
			return resp.Error()
		}
	}

	return nil
}

func (vs *valkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}

	result := vs.cli.B().Zrangebyscore().Key(vs.expiryIndexKey).Min("-inf").Max(strconv.FormatInt(before.Unix(), 10)).Limit(0, limit).Build()
	sessionIDs, err := vs.cli.Do(ctx, result).AsStrSlice()
	if err != nil {
		return nil, err
	}

	return vs.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (vs *valkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}

	result := vs.cli.B().Zrangebyscore().Key(vs.lastActivityIndexKey).Min("-inf").Max(strconv.FormatInt(before.Unix(), 10)).Limit(0, limit).Build()
	sessionIDs, err := vs.cli.Do(ctx, result).AsStrSlice()
	if err != nil {
		return nil, err
	}

	return vs.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (vs *valkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return &StoreError{Message: "sessionID cannot be empty"}
	}

	if at.IsZero() {
		at = time.Now()
	}

	key := vs.sessionKey(sessionID)
	existsCmd := vs.cli.B().Exists().Key(key).Build()
	exists, err := vs.cli.Do(ctx, existsCmd).AsInt64()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	zaddCmd := vs.cli.B().Zadd().Key(vs.lastActivityIndexKey).ScoreMember().ScoreMember(float64(at.Unix()), sessionID).Build()
	_ = vs.cli.Do(ctx, zaddCmd)

	return nil
}

func (vs *valkeyStore) Close() error {
	if vs.cli != nil {
		vs.cli.Close()
	}
	return nil
}

func (vs *valkeyStore) sessionKey(sessionID string) string {
	return vs.sessionPrefix + sessionID
}

func (vs *valkeyStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, sid := range sessionIDs {
		keys[i] = vs.sessionKey(sid)
	}

	result := vs.cli.B().Mget().Key(keys...).Build()
	values, err := vs.cli.Do(ctx, result).AsStrSlice()
	if err != nil {
		klog.V(4).Infof("valkey MGET error: %v", err)
		values = make([]string, len(keys))
	}

	var resultSandboxes []*types.SandboxInfo
	for i, val := range values {
		if val == "" {
			continue
		}

		var sandbox types.SandboxInfo
		if err := json.Unmarshal([]byte(val), &sandbox); err != nil {
			klog.V(4).Infof("unmarshal sandbox %s failed: %v", sessionIDs[i], err)
			continue
		}
		resultSandboxes = append(resultSandboxes, &sandbox)
	}

	return resultSandboxes, nil
}

